SELECT COUNT(*) AS film_count
FROM movies
WHERE Distributor = 'Warner Bros.';

SELECT COUNT(*) AS days_count
FROM seattle_weather
WHERE temp_max > 30;

SELECT
  100.0 * SUM(CASE WHEN order_status = 'canceled' THEN 1 ELSE 0 END) / COUNT(*) AS pct_canceled
FROM olist_orders;

SELECT quantile(fare_amount, 0.25) AS p25_fare_amount FROM nyc_taxi WHERE fare_amount IS NOT NULL; SELECT median(fare_amount) AS median_fare_amount FROM nyc_taxi WHERE fare_amount IS NOT NULL; SELECT quantile_cont(fare_amount, 0.9) AS p90_fare_amount
FROM nyc_taxi
WHERE fare_amount IS NOT NULL;

SELECT COUNT(*) AS order_count
FROM olist_orders
WHERE date_part('year', order_purchase_timestamp) = 2099;
